import numpy as np

class MultiLossQGAN:
    """QGAN with multiple loss function options."""

    def __init__(self, epsilon: float = 1e-7):
        self.eps = epsilon

    def generator_loss(self, d_fake: float, loss_type: str) -> float:
        """Compute generator loss based on type."""
        if loss_type == 'standard':
            # -log(D(G(z))): want to maximize D(G(z))
            return -np.log(d_fake + self.eps)

        elif loss_type == 'wasserstein':
            # -D(G(z)): want to maximize critic output
            return -d_fake

        elif loss_type == 'least_squares':
            # (D(G(z)) - 1)^2 / 2: want D(G(z)) = 1
            return 0.5 * (d_fake - 1) ** 2

        elif loss_type == 'hinge':
            # -D(G(z)): similar to Wasserstein
            return -d_fake

        else:
            raise ValueError(f"Unknown loss type: {loss_type}")

    def discriminator_loss(self, d_real: float, d_fake: float,
                           loss_type: str) -> float:
        """Compute discriminator loss based on type."""
        if loss_type == 'standard':
            # -[log(D(x)) + log(1 - D(G(z)))]
            real_loss = -np.log(d_real + self.eps)
            fake_loss = -np.log(1 - d_fake + self.eps)
            return (real_loss + fake_loss) / 2

        elif loss_type == 'wasserstein':
            # D(G(z)) - D(x): want D(x) > D(G(z))
            return d_fake - d_real

        elif loss_type == 'least_squares':
            # [(D(x) - 1)^2 + D(G(z))^2] / 2
            real_loss = (d_real - 1) ** 2
            fake_loss = d_fake ** 2
            return 0.5 * (real_loss + fake_loss)

        elif loss_type == 'hinge':
            # max(0, 1 - D(x)) + max(0, 1 + D(G(z)))
            real_loss = np.maximum(0, 1 - d_real)
            fake_loss = np.maximum(0, 1 + d_fake)
            return real_loss + fake_loss

        else:
            raise ValueError(f"Unknown loss type: {loss_type}")

    def compare_losses(self, d_real: float, d_fake: float) -> dict:
        """Compare all loss types for given discriminator outputs."""
        loss_types = ['standard', 'wasserstein', 'least_squares', 'hinge']

        result = {}
        for lt in loss_types:
            result[lt] = {
                'g_loss': self.generator_loss(d_fake, lt),
                'd_loss': self.discriminator_loss(d_real, d_fake, lt)
            }

        return result

# Test implementation
loss_fn = MultiLossQGAN()

print("Comparing losses for D(real)=0.8, D(fake)=0.3:")
result = loss_fn.compare_losses(d_real=0.8, d_fake=0.3)
for loss_type, losses in result.items():
    print(f"  {loss_type}: G={losses['g_loss']:.4f}, D={losses['d_loss']:.4f}")

print("\nComparing losses for balanced case D(real)=0.5, D(fake)=0.5:")
result = loss_fn.compare_losses(d_real=0.5, d_fake=0.5)
for loss_type, losses in result.items():
    print(f"  {loss_type}: G={losses['g_loss']:.4f}, D={losses['d_loss']:.4f}")
